      function CF_AGE_LESS_THAN55Formula return NUMBER is

V_NUMBER NUMBER;
BEGIN

	SELECT 	TRUNC(MONTHS_BETWEEN(:P_FACTITIOUS_DATE, DATE_OF_BIRTH)/12)
  INTO V_NUMBER
	FROM		REG_INSURED
	WHERE		REG_INSURED.INSURED_ID = :P_INSURED_ID ;

  IF V_NUMBER<55 THEN 
   RETURN 1;
  ELSE 
  	RETURN 0;
  END IF;
END;

      function CF_SEX_DESCRFormula return Char is

