      function CF_PROCCESS_IDFormula return Number is

V_PROCESS_ID NUMBER;

CURSOR CUR_PROCESS IS
SELECT A.PROCESS_ID
FROM PEN_SUMMARIZATION_PER_INSURED A
WHERE A.INSURED_ID = :P_INSURED_ID
ORDER BY A.PROCESS_ID DESC;

begin
	
	OPEN CUR_PROCESS;
	FETCH CUR_PROCESS
	INTO V_PROCESS_ID;
	CLOSE CUR_PROCESS;
	
  :P_PROCESS_ID:=V_PROCESS_ID;
  RETURN :P_PROCESS_ID;
end;

      function CF_YEARS_USEDFormula return Char is

TYPE T_YEARS_USED IS TABLE OF NUMBER INDEX BY BINARY_INTEGER;
YEARS T_YEARS_USED ;
I NUMBER:=1;
LINE VARCHAR2(200) :=''; --CONTAINTS YEARS WITH FORM 1999,2000,2001

CURSOR CUR_YEARS_USED IS
SELECT A.YEAR_USED
FROM PEN_SUMMAR_CLASS_YEARS A 
WHERE A.PROCESS_ID = :P_PROCESS_ID;

begin
  
  OPEN CUR_YEARS_USED;

   LOOP
	  FETCH CUR_YEARS_USED
	  INTO YEARS(I);
	  I:= I+1;
	  EXIT WHEN CUR_YEARS_USED%NOTFOUND;  
   END LOOP;

  FOR K IN 1..YEARS.COUNT LOOP
  if k!=years.count then 
     LINE := LINE || TO_CHAR(YEARS(K)) || ',';     
  else
    LINE := LINE || TO_CHAR(YEARS(K));     
  end if;
  END LOOP;
  
  CLOSE CUR_YEARS_USED;
  
  RETURN LINE;
  
end;

      FUNCTION CF_FINAL_PEN_AMOUNTFormula RETURN NUMBER IS

V_INS_REDUCTION NUMBER;
V_WORK_INS_CHILD_INCR NUMBER;

CURSOR cur_amount IS
SELECT WORKING_INS_REDUCTION, WORK_INS_CHILD_INCR
FROM PEN_ACCOUNT
WHERE ACCOUNT_NO =  :P_ACC_ACCOUNT_NO;

BEGIN
  OPEN cur_amount;
  FETCH cur_amount
  INTO V_INS_REDUCTION,
       V_WORK_INS_CHILD_INCR;
  CLOSE cur_amount;
  
  RETURN :P_PENSION_AMOUNT -NVL(V_INS_REDUCTION,0) + NVL(V_WORK_INS_CHILD_INCR,0); 
END;

