      function CF_TROPOPIITIKI_DOCFormula return Char is
CURSOR C1 IS 
    Select Document_Code
    From Wrk_In_Out A
    Where A.Protocol_Orgbra_Code = :PDTA_APPLICATION_UNIT_CODE
    And A.Protocol_Year =:PDTA_APPLICATION_YEAR
    And A.Protocol_No = :PROTOCOL_NO
    And Nvl(A.Receive_Appl_Flg,'0') = '1'
    And A.Type_Flg = '1'
    And A.Status = '1'
    ;

