      function CF_KATALOGISMOS_TEXTFormula return Char is
TO_RETURN VARCHAR2(1000);
V_00597  VARCHAR2(1);
V_00599  VARCHAR2(1);
begin
	IF :CP_AWARD_TYPE='8' THEN
		TO_RETURN:='Συμψηφίζουμε κάθε ποσό που εισέπραξε ο/η ανωτέρω με την '||:CP_CONV_DECISION||' απόφαση, με τα ποσά που δικαιούται με την παρούσα απόφαση.'||chr(10)||chr(10);
    V_00597 := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
			 0,:p_form_id,'00001','00318','00597');
		V_00599 := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
			 0,:p_form_id,'00001','00318','00599');	 
		IF V_00597='1' AND V_00599='0' THEN
			TO_RETURN:=TO_RETURN||'Καταλογίζουμε τα αχρεωστήτως καταβληθέντα ποσά συντάξεων έντοκα προς 5% απο την έναρξη καταβολής της σύνταξης και όχι πέραν της  20ετίας με παρακράτηση του 1/4 της μηνιαίας σύνταξης και μέχρι εξόφλησης της οφειλής.';
		ELSIF V_00597='1' AND V_00599='1'	THEN
			TO_RETURN:=TO_RETURN||'Καταλογίζουμε τα αχρεωστήτως καταβληθέντα ποσά συντάξεων έντοκα προς 5% απο την ημερομηνία οριστικοποίησης της απόφασης, με παρακράτηση του 1/4 της μηνιαίας σύνταξης και μέχρι εξόφλησης της οφειλής.';
		END IF;	
	ELSE
		 TO_RETURN:='';
	END IF;	 
	RETURN TO_RETURN;		 
end;

