function AfterPForm return boolean is
cursor c1 is SELECT --decode(COM_ORG_BRANCHES.BRANCH_CODE,'09930','ΓΕΝΙΚΗ ΔΙΕΥΘΥΝΣΗ ΣΥΝΤΑΞΕΩΝ ΔΗΜΟΣΙΟΥ',COM_ORG_BRANCHES.BRANCH_NAME) COM_ORG_BRANCHES.BRANCH_NAME, COM_ORG_BRANCHES.BRANCH_CODE FROM REG_INSURED, PEN_APPLICATION_INSTANCES, COM_ORG_BRANCHES, PEN_QC_PER_PRODINST, PEN_PRODUCT_PER_INSTITUTIONS, PEN_PRODUCTS, COM_PENSION_IKA_INSTITUTION WHERE PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO=:P_APPL_INCR_SEQ_NO AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE=:P_APPL_UNIT_CODE AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001' AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR=:P_APPL_YEAR AND PEN_APPLICATION_INSTANCES.INSURED_ID=:P_INSURED_ID AND REG_INSURED.INSURED_ID=PEN_APPLICATION_INSTANCES.INSURED_ID AND PEN_QC_PER_PRODINST.QC_PER_PRODINST_CODE=:P_QC_PER_PRODINST AND PEN_QC_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE AND COM_PENSION_IKA_INSTITUTION.PENSION_IKA_INST_CODE=PEN_PRODUCT_PER_INSTITUTIONS.INSTITUTION_CODE AND PEN_PRODUCTS.PRODUCT_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE AND COM_ORG_BRANCHES.BRANCH_CODE=:P_DT_DEC_UNIT_CODE;
begin open c1; fetch c1 into :p_branch_name, :p_branch_code; close c1;
if :p_branch_code = '00054' then if :p_commit_date <= to_date('18/06/2020','dd/mm/yyyy') then :p_branch_name := 'ΠΕΡΙΦΕΡΕΙΑΚΗ ΔΙΕΥΘΥΝΣΗ ΣΥΝΤΑΞΕΩΝ Ν.Π.Δ.Δ.'; elsif :p_commit_date >= to_date('19/06/2020','dd/mm/yyyy') then :p_branch_name := 'Β''''Δ/ΝΣΗ ΑΠΟΝΟΜΗΣ ΣΥΝΤΑΞΕΩΝ & ΕΦΑΠΑΞ ΔΗΜΟΣΙΟΥ ΤΟΜΕΑ'; :P_BRANCH_2_00054 := 'Tμήμα:Α''''ΤΜ. ΑΠΟΝΟΜΗΣ ΚΥΡΙΑΣ ΣΥΝΤΑΞΗΣ, ΕΠΙΚΟΥΡΙΚΗΣ & ΕΦΑΠΑΞ ΠΑΡΟΧΗΣ - ΝΠΔΔ' ; end if; end if;
return (TRUE);
return (TRUE); end;
